        "content": [
          "* in cursor use only isActive = true\r\n",
          "* user in copilot is: LEFT(`login`, POSITION('-tr' IN `login`) - 1)\r\n",
          "      ELSE `login`\r\n",
          "* user in cursor: POSITION('@' IN `email`) - 1)      "
        ]
      }
    ],
    "example_question_sqls": [
      {
        "id": "01f0c901655c1c73947f5aa2998f6b52",
        "question": [
          "give me all users in cursor and copilot"
        ],
        "sql": [
          "this are the users in copilot and cursor:\r\n",
          "\r\n",
          "SELECT DISTINCT\r\n",
          "  LEFT(`email`, POSITION('@' IN `email`) - 1) AS user\r\n",
          "FROM\r\n",
          "  `main`.`github`.`cursor_usage`\r\n",
          "UNION\r\n",
          "SELECT DISTINCT\r\n",
          "  CASE\r\n",
          "    WHEN POSITION('-tr' IN `login`) > 0 THEN LEFT(`login`, POSITION('-tr' IN `login`) - 1)\r\n",
          "    ELSE `login`\r\n",
          "  END AS user\r\n",
          "FROM\r\n",
          "  `main`.`github`.`github_copilot_seatsusage`"
        ]
      }
    ]
